public void testPrefixMapSize() {
    Trie<String, Integer> trie = new PatriciaTrie<Integer>();
    trie.put("Anna", 1);
    trie.put("Anael", 2);
    trie.put("Analu", 3);
    trie.put("Andreas", 4);
    trie.put("Andrea", 5);
    trie.put("Andres", 6);
    trie.put("Anatole", 7);
    SortedMap<String, Integer> prefixMap = trie.prefixMap("And");
    assertEquals(3, prefixMap.size());

    prefixMap.remove("Andrea");
    assertEquals(2, prefixMap.size());
    assertEquals(6, trie.size());
    assertEquals(new HashSet<String>(Arrays.asList("Anael", "Analu", "Anatole", "Anna", "Andreas", "Andres")), trie.keySet());
}

public void testPrefixMapContainsKey() {
    Trie<String, Integer> trie = new PatriciaTrie<Integer>();
    trie.put("Anna", 1);
    trie.put("Andreas", 4);
    trie.put("Andrea", 5);
    trie.put("Andres", 6);
    SortedMap<String, Integer> prefixMap = trie.prefixMap("And");

    assertTrue(prefixMap.containsKey("Andrea"));
    assertTrue(prefixMap.containsKey("Andreas"));
    assertTrue(prefixMap.containsKey("Andres"));
    assertFalse(prefixMap.containsKey("Anna"));
    assertFalse(prefixMap.containsKey("An"));
}

public void testPrefixMapPutAll() {
    Trie<String, Integer> trie = new PatriciaTrie<Integer>();
    trie.put("Anna", 1);
    trie.put("Andreas", 4);
    SortedMap<String, Integer> prefixMap = trie.prefixMap("And");

    Map<String, Integer> newEntries = new HashMap<String, Integer>();
    newEntries.put("Andrea", 5);
    newEntries.put("Andres", 6);
    prefixMap.putAll(newEntries);

    assertEquals(2, prefixMap.size());
    assertEquals(Integer.valueOf(5), prefixMap.get("Andrea"));
    assertEquals(Integer.valueOf(6), prefixMap.get("Andres"));
    assertEquals(3, trie.size());
}
